import React, {useRef, useState, useEffect} from 'react'
import styled from 'styled-components'
import Header from './Header'
import Navbar from './Navbar'
import {getDesigner, getSize, /*getDepartment,*/ getCondition, getCategory, getSubCategory, createListing} from '../WebAPI.js'


const Item = styled.div `
width:100%;
height:140px;
border-top:1px solid rgb(200, 200, 200);
border-bottom:1px solid rgb(200, 200, 200);
font-size:0.9rem;
display:flex;
align-items:center;
justify-content:space-between;
`

const ItemImage = styled.div `
width:70px;
height:100px;
background-image:url(${props => props.image ? props.image : null});
background-position:center;
background-size:cover;
`

const ItemDescription = styled.div `
display:flex;
flex-direction:column;
margin-left:40px;
`

const Title = styled.div `
font-weight:800;
`

const Size = styled.div `
color:grey;
`

const ItemPrice = styled.div  `
&::before {
	content:'$'
}
` 

const Div = styled.div `
display:flex;
align-items:center;
`

const Seller = styled.div `
font-size:0.8rem;
margin-top:40px;
`

export default function SingleOrderSection ({listing}) {

	return (
		<Item>
			<Div>
				<ItemImage image={listing.image_1}/>
				<ItemDescription>
					<Title>{listing.itemName}</Title>
					<Size>{listing.sizeName}</Size>
					<Seller>Seller : {listing.sellerName}</Seller>
				</ItemDescription>
			</Div>
			<ItemPrice>{listing.price}</ItemPrice>
		</Item>	
	)
}
